```ebnf
Program = { Statement } ;

Statement = Expression ;

Expression = Literal | Identifier | "(" Expression { " " Expression } ")" ;

Literal = Number | String | Boolean ;

Number = [ "0" | "1" | ... | "9" ] ;
String = " ( (" [ ^"\\"] | "\\." | "\\n" | "\\r" | "\\t" )* )" ;
Boolean = "true" | "false" ;

// Note: Comments are handled during the lexical pass and are not part of the core grammar structure itself.
```
